import React from 'react';
import { Heart } from 'lucide-react';
import ParamHeader from './ParamHeader';

function DateCounter({ dateCount, onDateClick, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between">
        <ParamHeader
          paramKey="dateCount"
          label="约会次数"
          iconColor="text-rose-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.dateCount = el}
        />
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1">
            {[...Array(Math.min(dateCount, 5))].map((_, i) => (
              <Heart
                key={i}
                className="text-rose-400 fill-rose-400 animate-pulse"
                size={16}
                style={{ animationDelay: `${i * 0.1}s` }}
              />
            ))}
          </div>
          <span className="text-2xl font-bold text-rose-500 min-w-12 text-center">
            {dateCount}
          </span>
          <button
            onClick={onDateClick}
            className="group relative px-4 py-2 bg-gradient-to-r from-rose-400 to-pink-500 text-white font-bold rounded-xl hover:scale-110 active:scale-95 transition-all shadow-lg hover:shadow-xl"
          >
            <span className="relative z-10">+1</span>
            <div className="absolute inset-0 bg-gradient-to-r from-rose-500 to-pink-600 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity" />
          </button>
        </div>
      </div>
    </div>
  );
}

export default DateCounter;
